import re
import sys
import psycopg2
from psycopg2 import sql

SAFE_EXTENSION_RE = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

def validate_extension_name(name: str) -> str:
    if not name:
        raise ValueError("Extension name is required")
    if not SAFE_EXTENSION_RE.fullmatch(name):
        raise ValueError("Invalid extension name")
    return name

def create_extension(conn, extension_name: str):
    extension_name = validate_extension_name(extension_name)
    with conn.cursor() as cur:
        cur.execute(
            sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
                sql.Identifier(extension_name)
            )
        )
    conn.commit()

