    port = sys.argv[2]
    dbname = sys.argv[3]
    user = sys.argv[4]
    password = sys.argv[5]
    extensions = sys.argv[6:]

    if not extensions:
        extensions_input = input("Enter extension names separated by commas: ").strip()
        extensions = [e.strip() for e in extensions_input.split(",") if e.strip()]

    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
    )

